      resolved_config: resolvedConfig,
      workflow_config: {
        ...resolvedConfig,
        config_version: CONFIG_VERSION
      },
      normalized_payload: sanitizePayloadForLogs(normalizedPayload),
      raw_payload: sanitizedRawPayload
    }
  }];
}

return [{
  json: {
