    return asString;
  }

  if (/(token|authorization|password|secret|api key|api token)/.test(keyNorm)) {
    return '[REDACTED]';
  }

  if (/(email|mail)/.test(keyNorm)) {
    return maskEmail(asString);
  }

  if (/(phone|whatsapp|telefone|celular|ddi)/.test(keyNorm)) {
