  }

  if (normalized === 'phone_only') {
    return await findContactIdByPhone(normalizedPayload.phone);
  }

  if (normalized === 'email_only') {
    return await findContactIdByEmail(normalizedPayload.email);
  }

  return (await findContactIdByPhone(normalizedPayload.phone)) || (await findContactIdByEmail(normalizedPayload.email));
