function normalizeKey(value) {
  return String(value || '')
    .trim()
    .toLowerCase()
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .replace(/[?!:;,.()\[\]'"%]/g, '')
    .replace(/[-_/]/g, ' ')
    .replace(/\s+/g, ' ')
    .trim();
}

function normalizeListKey(value) {
  const base = normalizeKey(value);
  return base ? base.replace(/\s+/g, '_') : '';
}

function dedupeAliases(aliases) {
  const seen = new Set();
  const result = [];

  for (const alias of aliases || []) {
    const aliasText = String(alias || '').trim();
    if (!aliasText) {
      continue;
    }

    const normalizedAlias = normalizeKey(aliasText);
    if (!normalizedAlias || seen.has(normalizedAlias)) {
      continue;
    }

    seen.add(normalizedAlias);
    result.push(aliasText);
  }

  return result;
}

function mergeAliases(globalAliases, listAliases) {
  const merged = {};
  const keys = new Set([
    ...Object.keys(globalAliases || {}),
    ...Object.keys(listAliases || {})
  ]);

  for (const key of keys) {
    const globalEntries = Array.isArray(globalAliases?.[key]) ? globalAliases[key] : [];
    const listEntries = Array.isArray(listAliases?.[key]) ? listAliases[key] : [];
    merged[key] = dedupeAliases([...listEntries, ...globalEntries]);
  }

  return merged;
}

function pickValueByAliases(containers, aliases) {
  const normalizedAliases = new Set((aliases || []).map((alias) => normalizeKey(alias)).filter(Boolean));
  if (!normalizedAliases.size) {
    return '';
  }

  for (const container of containers) {
    for (const [rawKey, rawValue] of Object.entries(container || {})) {
      if (!normalizedAliases.has(normalizeKey(rawKey))) {
        continue;
      }

      if (rawValue === undefined || rawValue === null) {
        continue;
      }

      const value = String(rawValue).trim();
      if (value) {
        return value;
      }
    }
  }

  return '';
}

